        P(0) = 0
        for (i <- 0 until N) {
            P(i + 1) = P(i) + (if (nums(i) % 2 == 0) 1 else 0)
        }

        // Helper function to count evens in range [l, r] (inclusive)
        // Count = P[r+1] - P[l]
        val countEvensInRange = (l: Int, r: Int) => P(r + 1) - P(l)

        // Helper function to find j_max: largest index j in [l, r] such that nums[j] <= A
        def findJMax(l: Int, r: Int, A: Long): Int = {
            var low = l
            var high = r
            var jMax = -1

            while (low <= high) {
                val mid = low + (high - low) / 2
                if (nums(mid) <= A) {
                    jMax = mid
                    low = mid + 1 // Try to find a larger index
                } else {
                    high = mid - 1 // Must look left
                }
            }
            jMax
        }

        // Process queries
        val Q = queries.length
        val results = Array.ofDim[Long](Q)

        for (q <- 0 until Q) {
            val l = queries(q)(0).toInt
            val r = queries(q)(1).toInt
            val k = queries(q)(2).toLong()

            // Binary Search for i, such that A = 2*i is the answer.
            // We seek the smallest i such that i - C(2i) >= k

            // Lower bound for i is 1 (A=2).
            var lowI = 1L
            // Upper bound: k_max + N_max approx 10^9 + 10^5. 
            // We use a safe upper bound, e.g., 3 * 10^9, which corresponds to A ~ 6 * 10^9.
            var highI = 3_000_000_000L 
            var ansI = highI + 1L

            while (lowI <= highI) {
                val midI = lowI + (highI - lowI) / 2
                val A_mid = 2 * midI

                // 1. Find j_max: largest index j in [l, r] such that nums[j] <= A_mid
                val jMax = findJMax(l, r, A_mid)

                // 2. Calculate C(A_mid): count of evens in nums[l..jMax]
                var C_A_mid = 0
                if (jMax >= l) {
                    // C(A_mid) is the count of evens in nums[l..jMax]
                    C_A_mid = P(jMax + 1) - P(l)
                }

                // Check condition: Rank = i - C(2i)
                val rank = midI - C_A_mid

                if (rank >= k) {
                    // This i_mid might be the answer, try for a smaller one
                    ansI = midI
                    highI = midI - 1
                } else {
                    // Rank is too small, need a larger A
                    lowI = midI + 1
                }
            }

            // The result is A = 2 * ansI
            results(q) = 2 * ansI
        }

        results
    }
